args.query:
SELECT Symbol, "Company Description" AS company_name
FROM stockinfo
WHERE "Listing Exchange"='N' AND (ETF IS NULL OR ETF!='Y') AND ("Test Issue" IS NULL OR "Test Issue"!='Y') AND (Symbol IS NOT NULL) AND ("Company Description" IS NOT NULL);

